INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00277', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '加拿大犯罪學家 Pat Brantingham 及 Paul Brantingham 提出的「犯罪型態理論」（Crime Pattern Theory），是犯罪預防的重要理論之一。下列有關犯罪型態理論的敘述，何者正確？', '["本理論係結合理性選擇理論（RationalChoiceTheory）與生活方式暴露理論（LifestyleExposure Theory），對於犯罪發生的地點具有預測及解釋力", "本理論主要探究犯罪者與其所處的物理、社會環境之間，影響犯罪者選擇標的互動關係", "這兩位學者建構出一個由犯罪者居住地點、工作地點、遊蕩地點所組成的三角圖，說明犯罪者 會在這三個點的周遭及三條路徑旁，尋找或是發現犯罪機會", "本理論認為，標的物是否被潛在犯罪者發現或注意，主要是受到潛在犯罪者的個人特質與理性 選擇所影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00278', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '自1970年代後，學者開始著重政策執行的研究。學者Elmore（1978）將政策執行的組織研究分 為四種模式，下列針對這四種模式的敘述，何者錯誤？', '["系統管理模式（systemsmanagementmodel）強調組織的任務導向，並追求任務分配的均衡性與 合理性", "官僚過程模式（bureaucraticprocessmodel）認為，由於行政人員對承辦例行業務的熟悉，因而 瞭解其中可以使用裁量權限的空間，結果架空來自長官控制的力量", "組織發展模式（organizationaldevelopmentmodel）則是提出建立決策者和執行者之間共識的重 要，因此社區警政要求警察管理幹部視基層為內在顧客，擴大決策參與、尊重基層意見", "衝突妥協模式（conflictandbargainingmodel）則認為，組織成員為了爭取有限的資源，衝突成 為組織的常態。政策執行的過程則是反應參與者偏好與資源相互妥協的決定過程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00279', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '隨著對於被害者學研究之興起，刑事司法機構的執法人員都盡其職責以保護犯罪被害人及可能的 潛在被害人。警察為達到保障人民生命財產、實施公平正義的目的，也需要被害人的協助與配合。 下列有關犯罪被害人對於警察犯罪預防工作重要性之描述，何者錯誤？', '["藉由被害人及家屬提供的報案資料，有助於警察的破案率及社會秩序之維護", "警察對於被害人及家屬的協助，會改變他們對於警察的觀感，進而影響警民關係", "前次的被害經驗是預測未來被害的良好指標，因此警察針對被害人加強預防被害，可減少重複 被害的發生", "被害人希望警察在職責範圍內，依法行政，專注在案件的偵察與嫌犯的逮捕，對於被害人的情 緒反應，則不需要花費時間處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00280', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '進行風險分析時，包括犯罪風險分析，要考量三個重要的因素。下列何者錯誤？', '["外部環境因素（externalfactors）：考慮外部環境的影響，包括政治、經濟、社會和技術發展等， 對風險產生的影響", "弱點（vulnerability）：確認威脅的來源，例如那裡可能發生危險？如何發生？可能會有那些類 型的威脅產生", "可能性（probability）：分析可能導致危險發生的因素", "臨界點（criticality）：當發生危險時，決定結果嚴重性的程度。例如一般的竊盜案件與內賊所 為的竊盜案件，代表的意義則大不相同，嚴重性也不一樣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00281', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '「警察勤務區訪查作業規定」第三點，說明警勤區的訪查工作項目。下列敘述何者正確？', '["「查訪治安顧慮人口及記事人口，有效掌握其動態」屬於初級預防措施", "「輔導民眾加強安全防護能力，提供安全評估、安全設備建議、推展巡守組織及提倡守望相助 精神」屬於初級預防措施", "「發掘影響治安、婦幼、交通、安寧秩序之問題及事項，並與民眾合力解決及防範」屬於三級 預防措施", "「傳遞治安訊息，提高民眾自主防衛意識」屬於次級預防措施"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00282', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '綜觀現代警察建立後，警察於犯罪預防工作中角色的轉變，主要分成傳統警察時期，及1960年 代末之後的社區警政時期。下列關於社區警政時期的敘述，何者錯誤？', '["警察的角色從「秩序維護者」轉變為「社區服務者」", "警政重點由原先的「預防式」（proactive）警政轉變為「反應式」（reactive）處理案件的方式", "警察的工作範圍更為擴大，不再只是以犯罪為中心，也強調為民服務", "警察機關必須在結構上改進，同時必須鼓勵創新，提倡參與式管理，才能有效因應社區警政的要求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00283', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '在911恐怖攻擊事件後，所發展出來之「情報導向警政」（Intelligence-LedPolicing）已成為重要 的警政策略。下列有關情報導向警政的敘述，何者錯誤？', '["情報導向警政可視為社區警政與問題導向警政哲學之延伸，讓執法機關或人員在抗制、預防犯 罪上更具周延性", "社區警政蒐集資訊的目的是界定社區問題，而情報導向警政蒐集資訊是為了情報分析", "社區警政蒐集犯罪者資訊，幫助民眾預防犯罪、降低恐懼；情報導向警政在經由特定資訊篩選 出可能的威脅，通知民眾，以防止恐怖攻擊，也可降低恐懼", "電腦統計警政（COMPSTAT）關注環境的威脅（threatdriven）、著重策略分析，而情報導向警 政則是犯罪事件導向（incidentdriven）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00284', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'essay', '英文簡報文稿（25 分）
